import{_ as a,o as r,c as l,a2 as o}from"./chunks/framework.Bjylvv1V.js";const g=JSON.parse('{"title":"인사 관리 (입퇴사)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/hr-manage.md","filePath":"guide/scenarios/hr-manage.md","lastUpdated":null}'),e={name:"guide/scenarios/hr-manage.md"};function s(n,t,i,h,d,c){return r(),l("div",null,[...t[0]||(t[0]=[o(`<h1 id="인사-관리-입퇴사" tabindex="-1">인사 관리 (입퇴사) <a class="header-anchor" href="#인사-관리-입퇴사" aria-label="Permalink to &quot;인사 관리 (입퇴사)&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 건당 약 10분 | <strong>난이도</strong>: ★★☆ | <strong>주기</strong>: 수시 (입퇴사 발생 시)</p></blockquote><p>관리사무소 직원의 입사 등록, 근태 관리, 퇴사 처리, 각종 증명서 발급까지 인사 전반을 처리하는 프로세스입니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><h3 id="입사-처리" tabindex="-1">입사 처리 <a class="header-anchor" href="#입사-처리" aria-label="Permalink to &quot;입사 처리&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 인사기본정보 등록    (7분)  → 사원번호·성명·주민번호·부서·직급·입사일 입력</span></span>
<span class="line"><span>2. 급여기본정보 연동    (3분)  → 급여 구조 설정</span></span>
<span class="line"><span>3. 근태 관리 시작       (수시) → 연가·무급·조퇴·결근 입력</span></span></code></pre></div><h3 id="퇴사-처리" tabindex="-1">퇴사 처리 <a class="header-anchor" href="#퇴사-처리" aria-label="Permalink to &quot;퇴사 처리&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 퇴사일 입력         (2분)  → 인사기본정보에서 퇴사일 등록</span></span>
<span class="line"><span>2. 퇴직정산 연계       (별도) → 퇴직금 정산 프로세스 진행</span></span>
<span class="line"><span>3. 퇴직증명서 발급     (2분)  → 증명서출력 메뉴에서 출력</span></span></code></pre></div><h3 id="일상-업무" tabindex="-1">일상 업무 <a class="header-anchor" href="#일상-업무" aria-label="Permalink to &quot;일상 업무&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 근태관리 입력       (수시) → 근태 발생 시 즉시 입력</span></span>
<span class="line"><span>2. 입퇴사자현황 조회   (2분)  → 기간별 입퇴사 현황 확인</span></span>
<span class="line"><span>3. 인사기록카드 출력   (2분)  → 인사 이력 전체 조회</span></span></code></pre></div><hr><h2 id="입사-처리-1" tabindex="-1">입사 처리 <a class="header-anchor" href="#입사-처리-1" aria-label="Permalink to &quot;입사 처리&quot;">​</a></h2><h3 id="_1단계-인사기본정보-등록-7분" tabindex="-1">1단계: 인사기본정보 등록 (7분) <a class="header-anchor" href="#_1단계-인사기본정보-등록-7분" aria-label="Permalink to &quot;1단계: 인사기본정보 등록 (7분)&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/hr.html">인사관리</a> &gt; 인사기본정보 (PAY2010)</p></blockquote><p>직원의 기본 인사 정보를 시스템에 등록합니다.</p><h4 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h4><ol><li>인사기본정보 화면 진입</li><li><strong>신규</strong> 버튼 클릭</li><li>필수 항목 입력 (별표 <code>*</code> 표시 항목):</li></ol><table tabindex="0"><thead><tr><th>항목</th><th>입력 방법</th><th>비고</th></tr></thead><tbody><tr><td><strong>사원번호</strong></td><td>직접 입력</td><td>0001~1000 범위</td></tr><tr><td><strong>성명</strong></td><td>직접 입력</td><td></td></tr><tr><td><strong>주민번호</strong></td><td>직접 입력</td><td>입력 시 생년월일 자동 반영</td></tr><tr><td><strong>부서</strong></td><td>인사코드에서 선택</td><td></td></tr><tr><td><strong>직급</strong></td><td>인사코드에서 선택</td><td></td></tr><tr><td><strong>직종</strong></td><td>인사코드에서 선택</td><td></td></tr><tr><td><strong>입사일</strong></td><td>날짜 입력</td><td></td></tr></tbody></table><ol start="4"><li>연락처, 주소, 학력 등 추가 정보 입력</li><li><strong>저장</strong> 클릭</li></ol><h4 id="체크리스트" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h4><ul><li>[ ] 사원번호가 중복되지 않는가?</li><li>[ ] 주민번호가 정확한가? (생년월일 자동 반영 확인)</li><li>[ ] 부서·직급·직종이 인사코드에 등록된 값인가?</li><li>[ ] 입사일이 정확한가?</li><li>[ ] 별표(*) 필수 항목이 모두 입력되었는가?</li></ul><div class="tip custom-block"><p class="custom-block-title">인사코드 확인</p><p>부서, 직급, 직종은 인사코드에 등록된 항목만 선택할 수 있습니다. 새로운 부서나 직급이 필요하다면 먼저 인사코드를 등록하세요.</p></div><h3 id="_2단계-급여기본정보-연동-등록-3분" tabindex="-1">2단계: 급여기본정보 연동 등록 (3분) <a class="header-anchor" href="#_2단계-급여기본정보-연동-등록-3분" aria-label="Permalink to &quot;2단계: 급여기본정보 연동 등록 (3분)&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/salary.html">급여관리</a> &gt; 급여기본정보 (PAY3010)</p></blockquote><p>입사 등록 후 급여 계산에 필요한 급여 구조를 설정합니다.</p><ol><li>급여기본정보 화면 진입</li><li>신규 등록된 직원 선택</li><li>기본급, 각종 수당 입력</li><li>4대보험 정보 입력 (건강보험, 국민연금, 고용보험)</li><li><strong>저장</strong> 클릭</li></ol><div class="danger custom-block"><p class="custom-block-title">입사 즉시 등록</p><p>급여기본정보에 등록되지 않은 직원은 급여 계산에서 <strong>자동 제외</strong>됩니다. 입사 즉시 등록하세요.</p></div><p>상세 절차는 <a href="/guide/scenarios/payroll.html">급여 처리</a> 시나리오를 참고하세요.</p><hr><h2 id="퇴사-처리-1" tabindex="-1">퇴사 처리 <a class="header-anchor" href="#퇴사-처리-1" aria-label="Permalink to &quot;퇴사 처리&quot;">​</a></h2><h3 id="_1단계-퇴사일-입력-2분" tabindex="-1">1단계: 퇴사일 입력 (2분) <a class="header-anchor" href="#_1단계-퇴사일-입력-2분" aria-label="Permalink to &quot;1단계: 퇴사일 입력 (2분)&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/hr.html">인사관리</a> &gt; 인사기본정보 (PAY2010)</p></blockquote><ol><li>퇴사 직원 검색 후 선택</li><li><strong>퇴사일</strong> 입력</li><li>퇴사 사유 입력</li><li><strong>저장</strong> 클릭</li></ol><div class="warning custom-block"><p class="custom-block-title">퇴사일 입력 후 급여·퇴직 연계</p><p>퇴사일이 입력되면 해당 월 급여는 일할 계산됩니다. 퇴직정산은 별도 메뉴에서 진행해야 합니다.</p></div><h3 id="_2단계-퇴직정산-연계" tabindex="-1">2단계: 퇴직정산 연계 <a class="header-anchor" href="#_2단계-퇴직정산-연계" aria-label="Permalink to &quot;2단계: 퇴직정산 연계&quot;">​</a></h3><p>퇴직금 계산과 퇴직소득세 처리는 별도 프로세스입니다.</p><p>상세 절차는 <a href="/guide/scenarios/retirement.html">퇴직정산 처리</a> 시나리오를 참고하세요.</p><h3 id="_3단계-퇴직증명서-발급-2분" tabindex="-1">3단계: 퇴직증명서 발급 (2분) <a class="header-anchor" href="#_3단계-퇴직증명서-발급-2분" aria-label="Permalink to &quot;3단계: 퇴직증명서 발급 (2분)&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/hr.html">인사관리</a> &gt; 증명서출력 (PAY2140)</p></blockquote><ol><li>증명서출력 화면 진입</li><li>해당 직원 선택</li><li><strong>퇴직증명서</strong> 선택</li><li>출력 실행</li></ol><hr><h2 id="일상-업무-1" tabindex="-1">일상 업무 <a class="header-anchor" href="#일상-업무-1" aria-label="Permalink to &quot;일상 업무&quot;">​</a></h2><h3 id="근태관리" tabindex="-1">근태관리 <a class="header-anchor" href="#근태관리" aria-label="Permalink to &quot;근태관리&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/hr.html">인사관리</a> &gt; 근태관리 (PAY2020)</p></blockquote><p>직원의 연가, 무급휴가, 조퇴, 결근 등 근태 사항을 입력합니다.</p><h4 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h4><ol><li>근태관리 화면 진입</li><li>해당 직원 및 귀속 연월 선택</li><li>근태 유형 선택:</li></ol><table tabindex="0"><thead><tr><th>근태 유형</th><th>설명</th></tr></thead><tbody><tr><td><strong>연가</strong></td><td>유급 연차 휴가</td></tr><tr><td><strong>무급</strong></td><td>무급 휴가</td></tr><tr><td><strong>조퇴</strong></td><td>정규 퇴근 전 퇴근</td></tr><tr><td><strong>결근</strong></td><td>무단 결근</td></tr></tbody></table><ol start="4"><li>날짜 및 시간 입력</li><li><strong>저장</strong> 클릭</li></ol><div class="warning custom-block"><p class="custom-block-title">급여 계산 전 근태 입력 완료</p><p>근태 데이터는 <strong>급여 계산 전</strong>에 모두 입력해야 정확한 급여가 산정됩니다. 급여 계산 후 근태 수정 시 재계산이 필요합니다.</p></div><h3 id="입퇴사자현황-조회" tabindex="-1">입퇴사자현황 조회 <a class="header-anchor" href="#입퇴사자현황-조회" aria-label="Permalink to &quot;입퇴사자현황 조회&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/hr.html">인사관리</a> &gt; 입퇴사자현황 (PAY2110)</p></blockquote><p>기간별 입사자·퇴사자 현황을 조회합니다.</p><ol><li>조회 기간 설정</li><li>입사/퇴사 구분 선택 (전체/입사/퇴사)</li><li><strong>조회</strong> 클릭</li></ol><h3 id="인사기록카드" tabindex="-1">인사기록카드 <a class="header-anchor" href="#인사기록카드" aria-label="Permalink to &quot;인사기록카드&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/hr.html">인사관리</a> &gt; 인사기록카드 (PAY2130)</p></blockquote><p>직원의 인사 이력(입사, 부서 이동, 승진, 퇴사 등)을 전체적으로 확인합니다.</p><ol><li>해당 직원 선택</li><li><strong>조회</strong> 클릭</li><li>전체 이력 확인</li><li>필요 시 <strong>출력</strong> 클릭</li></ol><h3 id="증명서-출력" tabindex="-1">증명서 출력 <a class="header-anchor" href="#증명서-출력" aria-label="Permalink to &quot;증명서 출력&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/hr.html">인사관리</a> &gt; 증명서출력 (PAY2140)</p></blockquote><table tabindex="0"><thead><tr><th>증명서 종류</th><th>용도</th></tr></thead><tbody><tr><td><strong>재직증명서</strong></td><td>재직 사실 증명</td></tr><tr><td><strong>경력증명서</strong></td><td>근무 기간·부서·직급 증명</td></tr><tr><td><strong>퇴직증명서</strong></td><td>퇴직 사실 및 사유 증명</td></tr></tbody></table><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="사원번호가-중복되어-등록이-안-돼요" tabindex="-1">사원번호가 중복되어 등록이 안 돼요 <a class="header-anchor" href="#사원번호가-중복되어-등록이-안-돼요" aria-label="Permalink to &quot;사원번호가 중복되어 등록이 안 돼요&quot;">​</a></h3><p><strong>원인</strong>: 이미 사용 중인 사원번호 입력 <strong>해결</strong>: 입퇴사자현황(PAY2110) 또는 인사기본정보 목록에서 사용 중인 번호를 확인하고 다른 번호를 입력하세요.</p><h3 id="주민번호-입력-후-생년월일이-자동-입력되지-않아요" tabindex="-1">주민번호 입력 후 생년월일이 자동 입력되지 않아요 <a class="header-anchor" href="#주민번호-입력-후-생년월일이-자동-입력되지-않아요" aria-label="Permalink to &quot;주민번호 입력 후 생년월일이 자동 입력되지 않아요&quot;">​</a></h3><p><strong>원인</strong>: 주민번호 형식 오류 (하이픈 포함 등) <strong>해결</strong>: 주민번호를 하이픈(-) 없이 13자리 숫자만 입력하세요.</p><h3 id="근태-입력-후-급여-계산에-반영이-안-돼요" tabindex="-1">근태 입력 후 급여 계산에 반영이 안 돼요 <a class="header-anchor" href="#근태-입력-후-급여-계산에-반영이-안-돼요" aria-label="Permalink to &quot;근태 입력 후 급여 계산에 반영이 안 돼요&quot;">​</a></h3><p><strong>원인</strong>: 근태 입력 전에 이미 급여 계산이 완료된 경우 <strong>해결</strong>: 급여 계산을 취소하고, 근태 정보를 정확히 입력한 후 다시 계산하세요.</p><h3 id="부서·직급을-선택할-수-없어요" tabindex="-1">부서·직급을 선택할 수 없어요 <a class="header-anchor" href="#부서·직급을-선택할-수-없어요" aria-label="Permalink to &quot;부서·직급을 선택할 수 없어요&quot;">​</a></h3><p><strong>원인</strong>: 인사코드에 해당 항목이 등록되지 않은 경우 <strong>해결</strong>: <a href="/pay/common.html">공통정보관리</a>에서 인사코드를 먼저 등록하세요.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/pay/hr.html">인사관리</a> - 인사기본정보, 근태, 증명서</li><li><a href="/pay/salary.html">급여관리</a> - 급여기본정보, 급여 계산</li><li><a href="/pay/common.html">공통정보관리</a> - 인사코드, 부서·직급 코드</li><li><a href="/pay/retirement.html">퇴직정산</a> - 퇴직금 계산·정산</li><li><a href="/guide/scenarios/payroll.html">급여 처리</a> - 급여 처리 전체 프로세스</li><li><a href="/guide/scenarios/retirement.html">퇴직정산 처리</a> - 퇴직 정산 전체 프로세스</li></ul>`,74)])])}const u=a(e,[["render",s]]);export{g as __pageData,u as default};
